import scala.collection.immutable.Array

object Solution {
  def solve(nums: Array[Long]): Array[Long] = {
    val n = nums.length
    val ans = Array.fill(2 * n)(0L) // Initialize an array of size 2*n

    // First n elements are the same as nums
    for (i <- 0 until n) {
      ans(i) = nums(i)
    }

    // Last n elements are the reverse of nums
    for (i <- 0 until n) {
      // ans[i + n] = nums[n - 1 - i]
      ans(i + n) = nums(n - 1 - i)
    }

    ans
  }
}

